/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements template rendering, recipient validation, and a pluggable
 * transport layer. The default transport logs sends; inject a real
 * transport (SMTP, SendGrid, SES) for production use.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Transport function signature — abstracts the actual email delivery.
 * Return true for success, or throw/return false for failure.
 */
export type EmailTransport = (message: EmailMessage) => Promise<boolean>;

/**
 * A fully rendered email message ready for delivery.
 */
export interface EmailMessage {
  from: string;
  to: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Configuration for the EmailAdapter.
 */
export interface EmailAdapterConfig {
  /** Sender address for outgoing emails. */
  from: string;
  /** Optional custom transport. Defaults to logging transport. */
  transport?: EmailTransport;
}

/**
 * Email template definition — maps notification types to HTML/text renderers.
 */
interface EmailTemplate {
  renderHtml(payload: NotificationPayload): string;
  renderText(payload: NotificationPayload): string;
}

const EMAIL_TEMPLATES: Record<NotificationType, EmailTemplate> = {
  order_confirmation: {
    renderHtml(payload) {
      const items = payload.metadata?.items ?? '';
      const total = payload.metadata?.total ?? '';
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        `<h1>Order Confirmation</h1>`,
        `<p>Hello,</p>`,
        `<p>${escapeHtml(payload.body)}</p>`,
        items ? `<p><strong>Items:</strong> ${escapeHtml(items)}</p>` : '',
        total ? `<p><strong>Total:</strong> ${escapeHtml(total)}</p>` : '',
        `<p>Thank you for your order!</p>`,
        '</div>',
      ].join('\n');
    },
    renderText(payload) {
      return `Order Confirmation\n\n${payload.body}\n\nThank you for your order!`;
    },
  },

  order_status_update: {
    renderHtml(payload) {
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        `<h1>Order Status Update</h1>`,
        `<p>${escapeHtml(payload.body)}</p>`,
        '</div>',
      ].join('\n');
    },
    renderText(payload) {
      return `Order Status Update\n\n${payload.body}`;
    },
  },

  welcome: {
    renderHtml(payload) {
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        `<h1>Welcome to TaskFlow Pro!</h1>`,
        `<p>${escapeHtml(payload.body)}</p>`,
        `<p>We're glad to have you on board.</p>`,
        '</div>',
      ].join('\n');
    },
    renderText(payload) {
      return `Welcome to TaskFlow Pro!\n\n${payload.body}\n\nWe're glad to have you on board.`;
    },
  },

  account_update: {
    renderHtml(payload) {
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        `<h1>Account Update</h1>`,
        `<p>${escapeHtml(payload.body)}</p>`,
        '</div>',
      ].join('\n');
    },
    renderText(payload) {
      return `Account Update\n\n${payload.body}`;
    },
  },
};

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate that a recipient string is a plausible email address.
 */
export function isValidEmail(email: string): boolean {
  return EMAIL_REGEX.test(email);
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private readonly from: string;
  private readonly transport: EmailTransport;
  /** Sent messages — accessible for testing. */
  readonly sentMessages: EmailMessage[] = [];

  constructor(config: EmailAdapterConfig) {
    this.from = config.from;
    this.transport = config.transport ?? this.defaultTransport.bind(this);
  }

  /**
   * Send an email notification.
   *
   * 1. Validates the recipient address.
   * 2. Renders HTML and plain-text bodies from the template.
   * 3. Delivers via the configured transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!isValidEmail(payload.recipient)) {
      this.logger.warn(`Invalid recipient email: ${payload.recipient}`);
      return { success: false, error: `Invalid recipient email: ${payload.recipient}` };
    }

    const template = EMAIL_TEMPLATES[payload.type];
    const message: EmailMessage = {
      from: this.from,
      to: payload.recipient,
      subject: payload.subject,
      html: template.renderHtml(payload),
      text: template.renderText(payload),
    };

    try {
      const delivered = await this.transport(message);
      if (delivered) {
        this.sentMessages.push(message);
        this.logger.info(`Email sent to ${payload.recipient}: ${payload.subject}`);
        return { success: true };
      }
      this.logger.error(`Transport returned failure for ${payload.recipient}`);
      return { success: false, error: 'Transport delivery failed' };
    } catch (err: unknown) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown transport error';
      this.logger.error(`Transport error for ${payload.recipient}: ${errorMessage}`);
      return { success: false, error: errorMessage };
    }
  }

  /**
   * Render an email message from a payload without sending — useful for
   * previewing templates in dev/test.
   */
  renderMessage(payload: NotificationPayload): EmailMessage {
    const template = EMAIL_TEMPLATES[payload.type];
    return {
      from: this.from,
      to: payload.recipient,
      subject: payload.subject,
      html: template.renderHtml(payload),
      text: template.renderText(payload),
    };
  }

  /**
   * Default transport — logs the email and returns success.
   * Replaced with a real transport in production.
   */
  private async defaultTransport(message: EmailMessage): Promise<boolean> {
    this.logger.info(`[DefaultTransport] ${message.from} -> ${message.to}: ${message.subject}`);
    return true;
  }
}

