import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter, isValidEmail } from '../../src/adapters/email.adapter.js';
import type { EmailTransport, EmailMessage } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    type: 'order_confirmation',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'email',
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;
  let delivered: EmailMessage[];
  let transport: EmailTransport;

  beforeEach(() => {
    delivered = [];
    transport = async (msg) => {
      delivered.push(msg);
      return true;
    };
    adapter = new EmailAdapter({ from: 'noreply@taskflow.io', transport });
  });

  describe('send', () => {
    it('should deliver email through the transport', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(delivered).toHaveLength(1);
      expect(delivered[0]?.to).toBe('alice@example.com');
      expect(delivered[0]?.from).toBe('noreply@taskflow.io');
      expect(delivered[0]?.subject).toBe('Order Confirmation: order-1');
    });

    it('should track sent messages', async () => {
      await adapter.send(makePayload());
      expect(adapter.sentMessages).toHaveLength(1);
    });

    it('should return failure for invalid email', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient email');
      expect(delivered).toHaveLength(0);
    });

    it('should return failure when transport returns false', async () => {
      const failTransport: EmailTransport = async () => false;
      const failAdapter = new EmailAdapter({ from: 'x@y.com', transport: failTransport });

      const result = await failAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toBe('Transport delivery failed');
    });

    it('should catch transport errors and return failure', async () => {
      const errorTransport: EmailTransport = async () => {
        throw new Error('SMTP connection refused');
      };
      const errorAdapter = new EmailAdapter({ from: 'x@y.com', transport: errorTransport });

      const result = await errorAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
    });
  });

  describe('template rendering', () => {
    it('should render order_confirmation template with HTML', async () => {
      await adapter.send(makePayload());
      const msg = delivered[0]!;

      expect(msg.html).toContain('<h1>Order Confirmation</h1>');
      expect(msg.html).toContain('Your order has been placed');
      expect(msg.html).toContain('Thank you for your order');
    });

    it('should render order_confirmation plain text', async () => {
      await adapter.send(makePayload());
      const msg = delivered[0]!;

      expect(msg.text).toContain('Order Confirmation');
      expect(msg.text).toContain('Your order has been placed');
    });

    it('should render order_status_update template', async () => {
      await adapter.send(
        makePayload({
          type: 'order_status_update',
          subject: 'Order Update: order-1',
          body: 'Your order status has changed from pending to confirmed.',
        }),
      );
      const msg = delivered[0]!;

      expect(msg.html).toContain('<h1>Order Status Update</h1>');
      expect(msg.text).toContain('Order Status Update');
      expect(msg.text).toContain('pending to confirmed');
    });

    it('should render welcome template', async () => {
      await adapter.send(
        makePayload({
          type: 'welcome',
          subject: 'Welcome!',
          body: 'Welcome to the platform, Alice.',
        }),
      );
      const msg = delivered[0]!;

      expect(msg.html).toContain('Welcome to TaskFlow Pro');
      expect(msg.text).toContain("We're glad to have you on board");
    });

    it('should render account_update template', async () => {
      await adapter.send(
        makePayload({
          type: 'account_update',
          subject: 'Account Updated',
          body: 'Your email has been changed.',
        }),
      );
      const msg = delivered[0]!;

      expect(msg.html).toContain('<h1>Account Update</h1>');
      expect(msg.text).toContain('Your email has been changed');
    });

    it('should escape HTML in payload body', async () => {
      await adapter.send(
        makePayload({ body: '<script>alert("xss")</script>' }),
      );
      const msg = delivered[0]!;

      expect(msg.html).not.toContain('<script>');
      expect(msg.html).toContain('&lt;script&gt;');
    });

    it('should include metadata items and total in order_confirmation HTML', async () => {
      await adapter.send(
        makePayload({
          metadata: { items: 'Widget x2, Gadget x1', total: '$45.00' },
        }),
      );
      const msg = delivered[0]!;

      expect(msg.html).toContain('Widget x2, Gadget x1');
      expect(msg.html).toContain('$45.00');
    });
  });

  describe('renderMessage', () => {
    it('should render a message without sending', () => {
      const msg = adapter.renderMessage(makePayload());

      expect(msg.from).toBe('noreply@taskflow.io');
      expect(msg.to).toBe('alice@example.com');
      expect(msg.html).toContain('<h1>');
      expect(delivered).toHaveLength(0);
    });
  });

  describe('isValidEmail', () => {
    it('should accept valid emails', () => {
      expect(isValidEmail('alice@example.com')).toBe(true);
      expect(isValidEmail('bob+tag@sub.domain.com')).toBe(true);
    });

    it('should reject invalid emails', () => {
      expect(isValidEmail('')).toBe(false);
      expect(isValidEmail('not-an-email')).toBe(false);
      expect(isValidEmail('@missing-local.com')).toBe(false);
      expect(isValidEmail('missing-domain@')).toBe(false);
      expect(isValidEmail('spaces in@email.com')).toBe(false);
    });
  });

  describe('default transport', () => {
    it('should use default logging transport when none provided', async () => {
      const defaultAdapter = new EmailAdapter({ from: 'noreply@taskflow.io' });
      const result = await defaultAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(defaultAdapter.sentMessages).toHaveLength(1);
    });
  });

  describe('channel property', () => {
    it('should expose email channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });
});

